import { useReactiveRef } from '@guanghechen/react-hooks'
import { GomokuContextType } from '@kyokuya/react-game-gomoku-core'
import React from 'react'
import type { IPlayer } from '../core/players'
import { playerMap } from '../core/players'

export const useCurrentPlayer = (): React.MutableRefObject<IPlayer | null> => {
  const { state } = React.useContext(GomokuContextType)
  const currentPlayerType = state.players[state.currentPlayerId]?.type
  const currentPlayerRef = useReactiveRef<IPlayer | null>(
    currentPlayerType ? playerMap[currentPlayerType] : null,
  )
  return currentPlayerRef
}
