import shuffle from '@algorithm.ts/knuth-shuffle'
import type { IGomokuPieceData, IGomokuPlayer } from '@kyokuya/react-game-gomoku-core'
import { GomokuDirections, GomokuPlayerType } from '@kyokuya/react-game-gomoku-core'

export interface IPlayer {
  readonly type: GomokuPlayerType
  move(
    GOMOKU_SIZE: number,
    pieces: ReadonlyArray<IGomokuPieceData>,
    clickedCell?: { r: number; c: number },
  ): Promise<{ r: number; c: number } | null>
}

class HumanPlayer implements IPlayer {
  public readonly type = GomokuPlayerType.HUMAN
  public async move(
    _GOMOKU_SIZE: number,
    _pieces: ReadonlyArray<IGomokuPieceData>,
    clickedCell?: { r: number; c: number },
  ): Promise<{ r: number; c: number } | null> {
    if (clickedCell == null) return null
    const { r, c } = clickedCell
    return { r, c }
  }
}

class ComputerPlayer implements IPlayer {
  public readonly type = GomokuPlayerType.COMPUTER
  public async move(
    _GOMOKU_SIZE: number,
    _pieces: ReadonlyArray<IGomokuPieceData>,
  ): Promise<{ r: number; c: number }> {
    if (_pieces.length <= 0) {
      const m: number = _GOMOKU_SIZE >> 1
      return { r: m, c: m }
    }

    const pieces = _pieces.slice()
    shuffle(pieces)

    const directions = GomokuDirections.slice()
    shuffle(directions)

    for (const piece of pieces) {
      for (const [dr, dc] of directions) {
        const nr: number = piece.r + dr
        const nc: number = piece.c + dc
        if (pieces.find(piece => piece.r === nr && piece.c === nc)) continue
        return { r: nr, c: nc }
      }
    }
    return { r: -1, c: -1 }
  }
}

export const playerMap: Record<GomokuPlayerType, IPlayer> = {
  [GomokuPlayerType.HUMAN]: new HumanPlayer(),
  [GomokuPlayerType.COMPUTER]: new ComputerPlayer(),
}

export const defaultGomokuPlayerMap: Record<GomokuPlayerType, IGomokuPlayer> = Object.freeze({
  [GomokuPlayerType.HUMAN]: {
    type: GomokuPlayerType.HUMAN,
    name: 'human',
  },
  [GomokuPlayerType.COMPUTER]: {
    type: GomokuPlayerType.COMPUTER,
    name: 'computer',
  },
})
