import { GomokuInstructionType } from '../constant'
import type { IGomokuBoard, IGomokuInstruction, IGomokuPieceData } from '../types'

export function runInstructs(instructions: ReadonlyArray<IGomokuInstruction>): IGomokuPieceData[] {
  const pieces: IGomokuPieceData[] = []
  for (const instruction of instructions) {
    switch (instruction.type) {
      case GomokuInstructionType.RETRACT: {
        pieces.splice(pieces.length - instruction.payload, instruction.payload)
        break
      }
      case GomokuInstructionType.MOVE: {
        const { r, c, p } = instruction.payload
        pieces.push({ r, c, p })
        break
      }
      default:
    }
  }
  return pieces
}

export function calcGomokuBoard(
  GOMOKU_SIZE: number,
  pieces: ReadonlyArray<IGomokuPieceData>,
): IGomokuBoard {
  const board = new Uint8Array(GOMOKU_SIZE * GOMOKU_SIZE)
  for (const { r, c, p } of pieces) {
    // eslint-disable-next-line no-param-reassign
    board[r * GOMOKU_SIZE + c] = p + 1
  }
  return board
}
